// TanStack Query hooks for time entries
// Files: src/hooks/useTimeEntries.ts, src/hooks/useTimeEntryMutations.ts, src/hooks/useTimeEntrySummary.ts

// Import from '@/hooks'

// useTimeEntries - Infinite query with cursor-based pagination
export interface TimeEntriesPage {
  data: TimeEntry[];
  nextCursor: string | null;
  hasMore: boolean;
}
export interface UseTimeEntriesOptions {
  filters?: TimeEntryFilters;
  pageSize?: number;
  enabled?: boolean;
  staleTime?: number;
}
export function useTimeEntries(options?: UseTimeEntriesOptions): UseInfiniteQueryResult<InfiniteData<TimeEntriesPage>>;
export class TimeEntriesFetchError extends Error { code?: string; }

// useTimeEntryMutations - CRUD mutations with optimistic updates
export interface UpdateTimeEntryParams { id: string; data: UpdateTimeEntryInput; }
export function useCreateTimeEntry(options?: UseCreateTimeEntryOptions): UseMutationResult<TimeEntry, TimeEntryMutationError, CreateTimeEntryInput>;
export function useUpdateTimeEntry(options?: UseUpdateTimeEntryOptions): UseMutationResult<TimeEntry, TimeEntryMutationError, UpdateTimeEntryParams>;
export function useDeleteTimeEntry(options?: UseDeleteTimeEntryOptions): UseMutationResult<void, TimeEntryMutationError, string>;
export class TimeEntryMutationError extends Error { code?: string; details?: unknown; }

// useTimeEntrySummary - Aggregated data
export interface TimeEntrySummary {
  totalSeconds: number;
  totalHours: number;
  entryCount: number;
  averageDurationSeconds: number | null;
  averageDurationHours: number | null;
}
export interface TimeEntrySummaryParams { dateStart: string; dateEnd: string; categoryId?: string | null; }
export function useTimeEntrySummary(options: UseTimeEntrySummaryOptions): UseQueryResult<TimeEntrySummary>;

// useTimeEntrySummaryWithBreakdown - Summary with category breakdown
export interface CategoryTimeBreakdown {
  categoryId: string | null;
  categoryName: string | null;
  categoryColor: string | null;
  totalSeconds: number;
  totalHours: number;
  entryCount: number;
  percentage: number;
}
export interface TimeEntrySummaryWithBreakdown extends TimeEntrySummary {
  categoryBreakdown: CategoryTimeBreakdown[];
}
export function useTimeEntrySummaryWithBreakdown(options: UseTimeEntrySummaryWithBreakdownOptions): UseQueryResult<TimeEntrySummaryWithBreakdown>;

// Behavior notes:
// - useTimeEntries uses cursor-based pagination with created_at as cursor
// - Entries are ordered by created_at descending (newest first)
// - All mutations validate with CreateTimeEntrySchema/UpdateTimeEntrySchema (NOT full TimeEntrySchema)
// - Mutations implement optimistic updates via onMutate/onError
// - RLS policies ensure user can only access their own entries (user_id not in queries)
